-- Aula 4: Comandos Básicos do Git
UPDATE lessons SET exercise_data = JSON_OBJECT(
  'title', 'Simulação de Comandos Git',
  'description', 'Escreva os comandos Git que você usaria para inicializar um repositório e fazer seu primeiro commit.',
  'initialCode', '// Simule os comandos Git escrevendo console.log() para cada comando\n// Exemplo: console.log("git init");\n\n',
  'testCases', JSON_ARRAY(
    JSON_OBJECT('input', 'console.log("git init"); console.log("git add ."); console.log("git commit -m primeiro commit");', 'expected', 'git init\ngit add .\ngit commit -m primeiro commit')
  )
) WHERE id = 4;

-- Aula 5: Branches e Merge
UPDATE lessons SET exercise_data = JSON_OBJECT(
  'title', 'Trabalhando com Branches',
  'description', 'Simule a criação de uma branch chamada "feature" e o merge dela na main.',
  'initialCode', '// Escreva os comandos para:\n// 1. Criar e mudar para a branch feature\n// 2. Voltar para main\n// 3. Fazer merge da feature\n\n',
  'testCases', JSON_ARRAY(
    JSON_OBJECT('input', 'console.log("git checkout -b feature"); console.log("git checkout main"); console.log("git merge feature");', 'expected', 'git checkout -b feature\ngit checkout main\ngit merge feature')
  )
) WHERE id = 5;

-- Aula 6: Resolução de Conflitos
UPDATE lessons SET exercise_data = JSON_OBJECT(
  'title', 'Identificar Conflitos',
  'description', 'Crie uma função que identifica se há conflitos em um código.',
  'initialCode', '// Crie uma função que retorna true se encontrar "<<<<<<" no texto\nfunction temConflito(codigo) {\n  // Seu código aqui\n}\n\nconsole.log(temConflito("código normal"));\nconsole.log(temConflito("<<<<<<< HEAD"));\n',
  'testCases', JSON_ARRAY(
    JSON_OBJECT('input', 'function temConflito(codigo) { return codigo.includes("<<<<<<<"); } console.log(temConflito("código normal")); console.log(temConflito("<<<<<<< HEAD"));', 'expected', 'false\ntrue')
  )
) WHERE id = 6;

-- Aula 7: Estrutura Básica HTML
UPDATE lessons SET exercise_data = JSON_OBJECT(
  'title', 'Criar Estrutura HTML',
  'description', 'Crie uma função que gera uma estrutura HTML básica.',
  'initialCode', '// Crie uma função que retorna uma string com HTML básico\nfunction gerarHTML(titulo) {\n  return `<!DOCTYPE html><html><head><title>${titulo}</title></head><body></body></html>`;\n}\n\nconsole.log(gerarHTML("Minha Página"));\n',
  'testCases', JSON_ARRAY(
    JSON_OBJECT('input', 'function gerarHTML(titulo) { return `<!DOCTYPE html><html><head><title>${titulo}</title></head><body></body></html>`; } console.log(gerarHTML("Minha Página"));', 'expected', '<!DOCTYPE html><html><head><title>Minha Página</title></head><body></body></html>')
  )
) WHERE id = 7;

-- Aula 8: CSS Básico
UPDATE lessons SET exercise_data = JSON_OBJECT(
  'title', 'Gerar Regra CSS',
  'description', 'Crie uma função que gera uma regra CSS para mudar a cor de um elemento.',
  'initialCode', '// Crie uma função que retorna uma regra CSS\nfunction gerarCSS(seletor, cor) {\n  // Retorne: "seletor { color: cor; }"\n}\n\nconsole.log(gerarCSS("h1", "blue"));\n',
  'testCases', JSON_ARRAY(
    JSON_OBJECT('input', 'function gerarCSS(seletor, cor) { return seletor + " { color: " + cor + "; }"; } console.log(gerarCSS("h1", "blue"));', 'expected', 'h1 { color: blue; }')
  )
) WHERE id = 8;

-- Aula 9: Flexbox
UPDATE lessons SET exercise_data = JSON_OBJECT(
  'title', 'Criar Layout Flexbox',
  'description', 'Crie uma função que gera CSS Flexbox para centralizar conteúdo.',
  'initialCode', '// Crie uma função que retorna CSS com display flex e justify-content center\nfunction cssFlexbox() {\n  // Seu código aqui\n}\n\nconsole.log(cssFlexbox());\n',
  'testCases', JSON_ARRAY(
    JSON_OBJECT('input', 'function cssFlexbox() { return "display: flex; justify-content: center;"; } console.log(cssFlexbox());', 'expected', 'display: flex; justify-content: center;')
  )
) WHERE id = 9;

